    // whose only date is release_date, even when that release_date string is later.
    const aliased = parseModelsDevCatalog({
      google: {
        id: "google",
        models: {
          "dup-model": { id: "dup-model", name: "Has last_updated", cost: { input: 1, output: 1 }, last_updated: "2025-12-01" },
        },
