    expect(merged[0]?.name).toBe("Newer release");
  });

  it("keeps the first-seen entry when neither duplicate carries any date", () => {
    const aliased = parseModelsDevCatalog({
      google: {
        id: "google",
        models: {
          "dup-model": { id: "dup-model", name: "First seen", cost: { input: 1, output: 1 } },
        },
      },
      "google-extra": {
        id: "google-extra",
        models: {
          "dup-model": { id: "dup-model", name: "Second seen", cost: { input: 2, output: 2 } },
        },
      },
    });

    const merged = mergeModelsAcrossSources(aliased, ["google", "google-extra"]);
    expect(merged).toHaveLength(1);
    expect(merged[0]?.name).toBe("First seen");
  });
});

import { z } from "zod";

const ShortcutSchema = z.object({
  key: z.string(),
  label: z.string(),
  disabled: z.boolean().optional(),
});
export type Shortcut = z.infer<typeof ShortcutSchema>;

export function areShortcutsEqual(a: Shortcut[], b: Shortcut[]): boolean {
  if (a === b) return true;
  if (a.length !== b.length) return false;

  for (let i = 0; i < a.length; i++) {
    const left = a[i]!;
    const right = b[i]!;
    if (left.key !== right.key || left.label !== right.label || left.disabled !== right.disabled) {
      return false;
    }
  }

  return true;
}

// "Navigate"/"Select"/"Quit" matches the rest of the keyboard model
// (`j/k Navigate` in review, `Enter Select` everywhere else). Both web and CLI
// consume this single constant.
export const MAIN_MENU_SHORTCUTS: Shortcut[] = [
  { key: "↑/↓", label: "Navigate" },
  { key: "Enter", label: "Select" },
  { key: "q", label: "Quit" },
];

// Shared settings-hub footer shortcuts consumed by both the web and CLI hubs.
export const SETTINGS_SHORTCUTS: Shortcut[] = [
  { key: "↑/↓", label: "Navigate" },
  { key: "Enter", label: "Edit" },
  { key: "Esc", label: "Back" },
];

